// Compose the final draft payload per the n8n callback contract.
// Same callback schema as the 18-node analysis-automation workflow's Compose Draft.
// Difference: input fields come directly from the MCP tool call (Claude Code)
// instead of being assembled from upstream HTTP/Code nodes.

const data = $input.first().json;

// Generate a job_id if Claude Code didn't supply one.
const jobId = data.jobId || `mcp-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;

// Czech month-year string for title + publication.heading metadata
const now = new Date();
const czechMonths = ['Leden','Únor','Březen','Duben','Květen','Červen','Červenec','Srpen','Září','Říjen','Listopad','Prosinec'];
const publicationMonth = `${czechMonths[now.getMonth()]} ${now.getFullYear()}`;
const isoMonth = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}`;

const draft = {
  title: `Sektorová analýza — NACE ${data.naceDivision} — ${publicationMonth}`,
  publication_month: isoMonth,
  publication: {
    heading: 'Sektorová analýza',
    opener_markdown: data.openerMarkdown,
    full_text_markdown: data.publicationBodyMarkdown || '',
    source: `Ekonomické a strategické analýzy České spořitelny — ${publicationMonth}`,
  },
  observations: data.observations,
  closing_actions: data.closingActions,
};

const callbackPayload = {
  jobId,
  status: 'done',
  draft,
};

// Read callback URL from Static Data so Claude Code doesn't need to know it.
const workflowData = $getWorkflowStaticData('global');
const callbackUrl = workflowData.APP_CALLBACK_URL || '';
if (!callbackUrl) {
  throw new Error('APP_CALLBACK_URL is not configured. Set it in workflow Static Data.');
}

return [{
  json: { callbackUrl, callbackPayload, jobId }
}];

// Sign the callback payload with HMAC-SHA256 using N8N_CALLBACK_SECRET.
// Same logic as the 18-node workflow's Sign Callback node — produces the
// X-Signature-256 header value the app's /api/admin/briefs/from-n8n route
// validates before accepting the draft.
const crypto = require('crypto');

const workflowData = $getWorkflowStaticData('global');
const secret = workflowData.N8N_CALLBACK_SECRET || process.env.N8N_CALLBACK_SECRET || '';

if (!secret) {
  throw new Error('N8N_CALLBACK_SECRET is not configured. Set it in workflow Static Data.');
}

const data = $input.first().json;
const bodyStr = JSON.stringify(data.callbackPayload);
const sig = crypto.createHmac('sha256', secret).update(bodyStr, 'utf8').digest('hex');

return [{
  json: {
    callbackUrl: data.callbackUrl,
    callbackBody: bodyStr,
    signatureHeader: `sha256=${sig}`,
    jobId: data.jobId,
  }
}];

// Format the MCP tool's return value for Claude Code.
// Inspect the HTTP response from /api/admin/briefs/from-n8n and convert
// to a structured success/failure payload that Claude Code can interpret.

const input = $input.first();
const data = input.json;
const statusCode = data.statusCode ?? data.statusCode2 ?? 200;
const jobId = $('Sign Callback').first().json.jobId;

const body = data.body || data;

if (statusCode >= 200 && statusCode < 300) {
  return [{
    json: {
      success: true,
      jobId,
      message: `Draft brief written. Job ID: ${jobId}. Open /admin in the browser to review and publish.`,
      appResponse: body,
    }
  }];
}

return [{
  json: {
    success: false,
    jobId,
    statusCode,
    error: `Callback POST failed with status ${statusCode}.`,
    appResponse: body,
  }
}];
